// Extrai e normaliza dados da mensagem recebida
const body = $input.first().json.body || $input.first().json;
const from = body.from || body.number_whatsapp || body.data?.key?.remoteJid || '';
const message_text = body.text || body.message || body.data?.message?.conversation || body.data?.message?.extendedTextMessage?.text || '';
const media_type = body.mediaType || body.data?.messageType || null;
const media_url = body.mediaUrl || null;
const timestamp = body.timestamp || new Date().toISOString();

// Limpa número (remove @s.whatsapp.net)
const phone = from.replace('@s.whatsapp.net', '').replace(/\D/g, '');

return [{
  json: {
    phone,
    text: message_text || '',
    media_type,
    media_url,
    timestamp,
    language: 'pt-BR'
  }
}];

// Verifica se encontrou sessão existente ou precisa criar lead
const session = $input.first().json;
const phone = $('Parse Message').first().json.phone;

let user_id, lead_id, stage, fluxo_id, objecoes_count;

if (session && session.leads) {
  // Sessão existente
  user_id = session.leads.user_id;
  lead_id = session.leads.id;
  stage = session.leads.stage;
  fluxo_id = session.leads.fluxo_id;
  objecoes_count = session.leads.objecoes_count || 0;
} else if (Array.isArray(session) && session.length > 0 && session[0].leads) {
  user_id = session[0].leads.user_id;
  lead_id = session[0].leads.id;
  stage = session[0].leads.stage;
  fluxo_id = session[0].leads.fluxo_id;
  objecoes_count = session[0].leads.objecoes_count || 0;
} else {
  // Novo lead — precisa buscar user_id pelo número ou criar
  user_id = null;
  lead_id = null;
  stage = 'novo_contato';
  fluxo_id = '';
  objecoes_count = 0;
}

return [{
  json: {
    user_id,
    lead_id,
    stage,
    fluxo_id,
    objecoes_count,
    phone,
    is_new: !user_id
  }
}];

// Detecta tipo de agente: principal, prospecção, objeção ou extra
const session = $('Process Session').first().json;
const userDataRaw = $('Validate User').first().json;
const userData = Array.isArray(userDataRaw) ? userDataRaw[0] : userDataRaw;
const subscription = userData?.assinaturas?.[0] || userData?.assinaturas || {};

const objecoes_count = session.objecoes_count || 0;
const stage = session.stage || 'novo_contato';
const fluxo_id = session.fluxo_id || '';

let agent_type = 'principal';
let agent_index = 0;

if (stage === 'objecoes' || objecoes_count > 2) {
  agent_type = 'objecao';
} else if (stage === 'prospecao' || fluxo_id?.includes('prospec')) {
  agent_type = 'prospec';
} else if (subscription?.agentes_extras > 0 && fluxo_id?.match(/ae(\d)/)) {
  agent_type = 'extra';
  const match = fluxo_id.match(/ae(\d)/);
  agent_index = match ? parseInt(match[1]) : 0;
}

return [{
  json: {
    agent_type,
    agent_index,
    user_id: session.user_id,
    lead_id: session.lead_id,
    subscription_status: subscription?.status || 'unknown',
    creditos_tokens: subscription?.creditos_tokens || 0,
    addon_objecao: subscription?.addon_objecao || false
  }
}];

// Monta system prompt + seleciona provider e modelo dinâmico
const configArray = $('Busca Configs SDR').first().json;
const configs = Array.isArray(configArray) ? configArray : [];
const configMap = {};

configs.forEach(item => {
  if (item.chave && item.valor) configMap[item.chave] = item.valor;
});

const agentData = $('Detect Agent Type').first().json;
const agent_type = agentData.agent_type;
const agent_index = agentData.agent_index;
const prefix = agent_type === 'principal' ? '' : agent_type === 'prospec' ? 'prospec_' : agent_type === 'objecao' ? 'ob_' : `ae${agent_index}_`;

// Seleciona prompt base
let sistema_prompt = configMap[`${prefix}sistema_prompt`] || configMap['sistema_prompt'] || 'Você é um assistente de vendas profissional. Qualifique leads com critério.';

// Seleciona provider
const provider = configMap[`${prefix}ai_provider`] || configMap['ai_provider'] || 'openai';

// Seleciona modelo e parâmetros
let model, temperature, max_tokens;

if (provider === 'openai') {
  model = configMap[`${prefix}openai_model`] || configMap['openai_model'] || 'gpt-4o-mini';
  temperature = parseFloat(configMap[`${prefix}openai_temperature`] || configMap['openai_temperature'] || '0.7');
  max_tokens = parseInt(configMap[`${prefix}openai_max_tokens`] || configMap['openai_max_tokens'] || '1024');
} else if (provider === 'claude') {
  model = configMap[`${prefix}claude_model`] || configMap['claude_model'] || 'claude-haiku-4-5';
  temperature = parseFloat(configMap[`${prefix}claude_temperature`] || configMap['claude_temperature'] || '0.7');
  max_tokens = parseInt(configMap[`${prefix}claude_max_tokens`] || configMap['claude_max_tokens'] || '1024');
} else if (provider === 'google') {
  model = configMap[`${prefix}google_model`] || configMap['google_model'] || 'gemini-2.0-flash';
  temperature = parseFloat(configMap[`${prefix}google_temperature`] || configMap['google_temperature'] || '0.7');
  max_tokens = parseInt(configMap[`${prefix}google_max_tokens`] || configMap['google_max_tokens'] || '1024');
} else {
  model = 'gpt-4o-mini';
  temperature = 0.7;
  max_tokens = 1024;
}

// Append tonalidade
if (configMap[`${prefix}tonalidade`] || configMap['tonalidade']) {
  sistema_prompt += `\n\nTONALIDADE: ${configMap[`${prefix}tonalidade`] || configMap['tonalidade']}`;
}

// Append critérios
if (configMap[`${prefix}criterios_qualificacao`] || configMap['criterios_qualificacao']) {
  sistema_prompt += `\n\nCRITÉRIOS DE QUALIFICAÇÃO:\n${configMap[`${prefix}criterios_qualificacao`] || configMap['criterios_qualificacao']}`;
}

// Append instruções comunicação
if (configMap[`${prefix}instrucoes_comunicacao`] || configMap['instrucoes_comunicacao']) {
  sistema_prompt += `\n\nINSTRUÇÕES DE COMUNICAÇÃO:\n${configMap[`${prefix}instrucoes_comunicacao`] || configMap['instrucoes_comunicacao']}`;
}

return [{
  json: {
    final_system_prompt: sistema_prompt,
    ai_provider: provider,
    ai_model: model,
    ai_temperature: temperature,
    ai_max_tokens: max_tokens,
    msg_qualificado: configMap[`${prefix}msg_qualificado`] || configMap['msg_qualificado'] || 'Parabéns! Você foi qualificado.',
    msg_desqualificado: configMap[`${prefix}msg_desqualificado`] || configMap['msg_desqualificado'] || 'Obrigado pelo contato.',
    responder_em_audio: configMap[`${prefix}responder_em_audio`] || configMap['responder_em_audio'] || 'false',
    numero_destino: configMap[`${prefix}numero_destino`] || configMap['numero_destino'] || '',
    grupo_destino: configMap[`${prefix}grupo_destino`] || configMap['grupo_destino'] || '',
    notif_destino: configMap['notif_destino'] || 'numero'
  }
}];

// Monta array de mensagens para a LLM
const historyRaw = $('Load Conversation History').first().json;
const history = Array.isArray(historyRaw) ? historyRaw : [];
const promptData = $('Build System Prompt').first().json;
const userMessage = $('Parse Message').first().json.text;
const agentData = $('Detect Agent Type').first().json;

// Monta messages array
const messages = [{ role: 'system', content: promptData.final_system_prompt }];

// Adiciona histórico (invertido para ordem cronológica)
const historyReversed = [...history].reverse();
for (const msg of historyReversed) {
  messages.push({
    role: msg.sender === 'assistant' ? 'assistant' : 'user',
    content: msg.conteudo
  });
}

// Adiciona mensagem atual
messages.push({ role: 'user', content: userMessage });

return [{
  json: {
    provider: promptData.ai_provider,
    model: promptData.ai_model,
    temperature: promptData.ai_temperature,
    max_tokens: promptData.ai_max_tokens,
    messages,
    user_id: agentData.user_id
  }
}];

// Processa resposta da LLM e detecta qualificação + objeções + pagamento
const llmResponse = $('LLM Call').first().json;
const response_text = llmResponse.content || llmResponse.choices?.[0]?.message?.content || '';
const promptData = $('Build System Prompt').first().json;

// Detecta qualificação
const has_qualificado = response_text.includes('[LEAD_QUALIFICADO]');
const has_desqualificado = response_text.includes('[LEAD_DESQUALIFICADO]');

// Detecta objeções na mensagem do USUÁRIO
const userText = ($('Parse Message').first().json.text || '').toLowerCase();
const objection_keywords = ['não posso', 'muito caro', 'não sei', 'concorrente', 'depois', 'não tenho', 'sem interesse'];
let has_objection = false;
let objection_type = '';
for (const keyword of objection_keywords) {
  if (userText.includes(keyword)) {
    has_objection = true;
    if (keyword.includes('caro') || keyword.includes('não tenho')) objection_type = 'preco';
    else if (keyword.includes('depois')) objection_type = 'timing';
    else if (keyword.includes('concorrente')) objection_type = 'concorrente';
    else if (keyword.includes('sem interesse')) objection_type = 'interesse';
    else objection_type = 'outro';
    break;
  }
}

// Detecta intenção de pagamento
const payment_keywords = ['quero pagar', 'como pago', 'vou fechar', 'quero comprar', 'boleto', 'pix', 'cartão', 'parcelas', '[INICIAR_PAGAMENTO]'];
let payment_intent = false;
for (const keyword of payment_keywords) {
  if (response_text.toLowerCase().includes(keyword.toLowerCase()) || userText.includes(keyword.toLowerCase())) {
    payment_intent = true;
    break;
  }
}

// Limpa tags internas da resposta antes de enviar
let clean_response = response_text
  .replace('[LEAD_QUALIFICADO]', '')
  .replace('[LEAD_DESQUALIFICADO]', '')
  .replace('[INICIAR_PAGAMENTO]', '')
  .trim();

// Se qualificado/desqualificado, adiciona mensagem configurada
if (has_qualificado && promptData.msg_qualificado) {
  clean_response += '\n\n' + promptData.msg_qualificado;
}
if (has_desqualificado && promptData.msg_desqualificado) {
  clean_response += '\n\n' + promptData.msg_desqualificado;
}

return [{
  json: {
    response_text: clean_response,
    qualified: has_qualificado,
    disqualified: has_desqualificado,
    has_objection,
    objection_type,
    payment_intent,
    responder_em_audio: promptData.responder_em_audio === 'true',
    tokens_used: llmResponse.deducted_tokens || llmResponse.usage?.total_tokens || 0
  }
}];
